#!/usr/bin/env bash
set -euo pipefail

# ===========================================================================
# setup-worktree.sh — canonical worktree setup for the ticket-delivery flow.
#
# Deterministic so the orchestrator calls it instead of hand-rolling git
# worktree / env-copy / port math (where hallucination creeps in). Idempotent:
# re-running for an existing worktree reuses it.
#
# Usage:   setup-worktree.sh <TICKET_ID> <BRANCH>
# Example: setup-worktree.sh HEL-55 feature/panel-dup/HEL-55
#
# Reads project config from .concertino.env (next to this script), generated by
# `concertino sync`:
#   CONCERTINO_WORKTREE_BASE     dir (repo-relative) to hold worktrees
#   CONCERTINO_BASE_BRANCH       branch new worktree branches are cut from
#   CONCERTINO_FRONTEND_PORT_BASE / CONCERTINO_BACKEND_PORT_BASE   port bases
#   CONCERTINO_ENV_FILES         space-separated files to copy into the worktree
#   CONCERTINO_WORKTREE_HOOKS    ;-separated commands to run inside the worktree
#
# CONCERTINO_BASE_REMOTE (default: origin) may be set in the environment.
#
# On success prints the stable READY contract (the orchestrator parses these):
#   READY worktree=<absolute path>
#   READY branch=<branch>
#   READY dev_port=<n>
#   READY backend_port=<n>
# Exits non-zero with "FAIL <reason>" on any error.
# ===========================================================================

TICKET_ID="${1:?usage: setup-worktree.sh <TICKET_ID> <BRANCH>}"
BRANCH="${2:?usage: setup-worktree.sh <TICKET_ID> <BRANCH>}"

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck disable=SC1091
[ -f "${SCRIPT_DIR}/.concertino.env" ] && source "${SCRIPT_DIR}/.concertino.env"

REPO_ROOT="$(git rev-parse --show-toplevel)"
cd "$REPO_ROOT"

WORKTREE_BASE="${CONCERTINO_WORKTREE_BASE:-.concertino/worktrees}"
FRONTEND_PORT_BASE="${CONCERTINO_FRONTEND_PORT_BASE:-5173}"
BACKEND_PORT_BASE="${CONCERTINO_BACKEND_PORT_BASE:-8080}"
BASE_REMOTE="${CONCERTINO_BASE_REMOTE:-origin}"
BASE_BRANCH="${CONCERTINO_BASE_BRANCH:-main}"

# Derive stable ports from the ticket number so parallel orchestrators never
# collide. e.g. ticket #55 with default bases -> dev 5228, backend 8135.
TICKET_NUM="${TICKET_ID##*-}"
if ! [[ "$TICKET_NUM" =~ ^[0-9]+$ ]]; then
  echo "FAIL could not derive numeric ticket id from '$TICKET_ID'" >&2
  exit 1
fi
DEV_PORT=$((FRONTEND_PORT_BASE + TICKET_NUM))
BACKEND_PORT=$((BACKEND_PORT_BASE + TICKET_NUM))

WORKTREE_PATH="${REPO_ROOT}/${WORKTREE_BASE}/${BRANCH}"

# Create the worktree (reuse if it already exists for this branch).
if git worktree list --porcelain | grep -qx "worktree ${WORKTREE_PATH}"; then
  echo "note: worktree already present, reusing ${WORKTREE_PATH}" >&2
elif git show-ref --verify --quiet "refs/heads/${BRANCH}"; then
  git worktree add "$WORKTREE_PATH" "$BRANCH"      # branch exists, attach
else
  # New branch: cut from the fetched remote base, never from whatever local HEAD
  # happens to be. In a burst of sequential tickets each PR squash-merges on the
  # remote while local <base> stays behind, so branching from HEAD silently
  # produces conflicts whenever two tickets touch the same file.
  # Resuming an existing branch (above) must never re-base — only this path syncs.
  if git fetch --quiet "$BASE_REMOTE" "$BASE_BRANCH" 2>/dev/null &&
    git show-ref --verify --quiet "refs/remotes/${BASE_REMOTE}/${BASE_BRANCH}"; then
    BASE_REF="${BASE_REMOTE}/${BASE_BRANCH}"
  elif git show-ref --verify --quiet "refs/heads/${BASE_BRANCH}"; then
    BASE_REF="$BASE_BRANCH"
    echo "note: could not fetch ${BASE_REMOTE}/${BASE_BRANCH} — cutting from local ${BASE_BRANCH}" >&2
  else
    BASE_REF="HEAD"
    echo "note: no ${BASE_BRANCH} ref found — cutting from HEAD" >&2
  fi
  # --no-track: branching off a remote ref would otherwise set upstream to
  # <remote>/<base>, so `git status` reports the new branch as "ahead of main"
  # and a stray `git pull` would merge base in. Delivery sets the real upstream
  # with `git push -u origin <branch>`.
  git worktree add --no-track "$WORKTREE_PATH" -b "$BRANCH" "$BASE_REF"
fi

# Copy env/secret files the app needs at boot but that aren't committed. Without
# these the dev server (and any login) fails. This is the step prose leaves implicit.
for f in ${CONCERTINO_ENV_FILES:-}; do
  if [ -f "${REPO_ROOT}/${f}" ]; then
    mkdir -p "$(dirname "${WORKTREE_PATH}/${f}")"
    cp -n "${REPO_ROOT}/${f}" "${WORKTREE_PATH}/${f}" 2>/dev/null || true
  else
    echo "note: ${REPO_ROOT}/${f} not found — app may need env set another way" >&2
  fi
done

# Run project-defined worktree hooks (e.g. `npx husky install`, `npm ci`).
if [ -n "${CONCERTINO_WORKTREE_HOOKS:-}" ]; then
  IFS=';' read -ra HOOKS <<< "$CONCERTINO_WORKTREE_HOOKS"
  for hook in "${HOOKS[@]}"; do
    hook="$(echo "$hook" | sed 's/^ *//;s/ *$//')"
    [ -z "$hook" ] && continue
    ( cd "$WORKTREE_PATH" && eval "$hook" >/dev/null 2>&1 ) || true
  done
fi

echo "READY worktree=${WORKTREE_PATH}"
echo "READY branch=${BRANCH}"
echo "READY dev_port=${DEV_PORT}"
echo "READY backend_port=${BACKEND_PORT}"
